// 1) 날짜 범위 계산
const today = new Date();
const weekAgo = new Date(today);
weekAgo.setDate(today.getDate() - 7);
const pad = (n) => String(n).padStart(2, '0');
const fmt = (d) => `${d.getFullYear()}.${pad(d.getMonth()+1)}.${pad(d.getDate())}`;
const standard_range = `${fmt(weekAgo)}~${fmt(today)}`;

// 2) HTML 취득
const html = $input.first().json.data ?? $input.first().json.body ?? '';
if (!html) throw new Error('HTML을 받지 못했습니다.');

// 3) <li> 단위 분리 — item_info 클래스 포함 블록만 선별
const liParts = html.split(/<li(?:\s[^>]*)?>/).slice(1);
const productParts = liParts.filter(p =>
  /\/product\/goods\/\d+/.test(p) &&
  /class="[^"]*item_info[^"]*"/.test(p)
);

// 4) goods_no 기준 중복 제거
const seen = new Set();
const uniqueParts = [];
for (const part of productParts) {
  const m = /\/product\/goods\/(\d+)/.exec(part);
  if (m && !seen.has(m[1])) {
    seen.add(m[1]);
    uniqueParts.push({ goods_no: m[1], seg: part });
  }
}

if (uniqueParts.length === 0) {
  throw new Error(`파싱 실패.\nHTML 첫 500자:\n${html.slice(0, 500)}`);
}

const stripTags = (s) => s.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const decodeHtml = (s) => s
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&#39;/g, "'").replace(/&quot;/g, '"').replace(/&nbsp;/g, ' ');

const items = [];
let autoRank = 1;

for (const { goods_no, seg } of uniqueParts.slice(0, 24)) {
  let title = '';
  const titleRe = new RegExp(`href="\\/product\\/goods\\/${goods_no}"[^>]*>([\\s\\S]*?)<\/a>`, 'gi');
  let tm;
  while ((tm = titleRe.exec(seg)) !== null) {
    const t = decodeHtml(stripTags(tm[1]));
    if (t.length > 2) { title = t; break; }
  }
  title = title.replace(/\s*새창이동.*$/i, '').trim();

  const rankM = /<em[^>]*>\s*(\d{1,2})\s*<\/em>/i.exec(seg);
  const ranking = rankM ? rankM[1] : String(autoRank);

  const priceM = /class="[^"]*info_price[^"]*"[\s\S]{0,400}?<strong[^>]*>[\s\S]{0,200}?<em[^>]*>([\d,]+)<\/em>/i.exec(seg);
  const price = priceM ? priceM[1] : '';

  const authM = /class="[^"]*\binfo_auth\b[^"]*"[\s\S]{0,300}?<a[^>]*>([^<]{1,50})<\/a>/i.exec(seg);
  const author = authM ? decodeHtml(authM[1].trim()) : '';

  const pubM = /class="[^"]*\binfo_pub\b[^"]*"[\s\S]{0,300}?<a[^>]*>([^<]{2,60})<\/a>/i.exec(seg);
  const publisher = pubM ? decodeHtml(pubM[1].trim()) : '';

  const plain = decodeHtml(stripTags(seg));
  const dateM = /(\d{4}년\s*\d{1,2}월)/.exec(plain);
  const pub_date = dateM ? dateM[1].replace(/\s+/g, ' ') : '';

  items.push({
    standard_range,
    ranking,
    goods_no,
    image_url: `=IMAGE("https://image.yes24.com/goods/${goods_no}")`,
    goods_url: `https://www.yes24.com/product/goods/${goods_no}`,
    title,
    price,
    author,
    publisher,
    pub_date,
  });
  autoRank++;
}

if (items.length === 0) {
  throw new Error('필터링 후 유효한 항목이 없습니다.');
}

return items.map(item => ({ json: item }));
